const express = require('express');
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');

const {
  MONGODB_URI = 'mongodb://127.0.0.1:27017/auth',
  JWT_SECRET = 'change-me',
  JWT_ISSUER = 'auth-service',
  JWT_AUDIENCE = 'mobile-app',
  JWT_EXPIRES_IN = '1h',
  PORT = 3000
} = process.env;

const app = express();
app.disable('x-powered-by');
app.use(express.json({ limit: '8kb' }));

mongoose.set('strictQuery', true);
mongoose.connect(MONGODB_URI, {
  maxPoolSize: 50,
  serverSelectionTimeoutMS: 5000
}).catch(() => {});

const userSchema = new mongoose.Schema(
  {
    username: { type: String, required: true, unique: true, index: true },
    passwordHash: { type: String, required: true }
  },
  { timestamps: false, versionKey: false }
);

const User = mongoose.model('User', userSchema);

function safeEqual(a, b) {
  const sa = String(a || '');
  const sb = String(b || '');
  const len = Math.max(sa.length, sb.length);
  let out = 0;
  for (let i = 0; i < len; i++) {
    out |= (sa.charCodeAt(i) | 0) ^ (sb.charCodeAt(i) | 0);
  }
  return out === 0 && sa.length === sb.length;
}

app.post('/api/login', async (req, res) => {
  try {
    const username = typeof req.body?.username === 'string' ? req.body.username.trim() : '';
    const password = typeof req.body?.password === 'string' ? req.body.password : '';

    if (!username || !password || username.length > 128 || password.length > 1024) {
      return res.status(400).json({ error: 'invalid_request' });
    }

    const user = await User.findOne({ username })
      .select({ _id: 1, username: 1, passwordHash: 1 })
      .lean();

    const fakeHash = '$2a$10$CwTycUXWue0Thq9StjUM0uJ8v7v4q1sVvSgN1l3pNGdisz8Iky3zS';
    const hashToCheck = user?.passwordHash || fakeHash;

    const ok = await bcrypt.compare(password, hashToCheck);

    if (!user || !ok) {
      return res.status(401).json({ error: 'invalid_credentials' });
    }

    const token = jwt.sign(
      { sub: String(user._id), username: user.username },
      JWT_SECRET,
      {
        algorithm: 'HS256',
        expiresIn: JWT_EXPIRES_IN,
        issuer: JWT_ISSUER,
        audience: JWT_AUDIENCE
      }
    );

    res.json({ token });
  } catch (e) {
    res.status(500).json({ error: 'server_error' });
  }
});

app.listen(Number(PORT), '0.0.0.0');